import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        response.setContentType("text/html");

        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");

        // Sanitize and encode user input to prevent XSS attacks
        String safeUserInput = sanitizeInput(userInput);

        out.println("<h1>User Input: " + safeUserInput + "</h1>");

        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper validation and encoding here
        // For example, you can use OWASP Java Encoder library for HTML encoding

        return org.owasp.encoder.Encode.forHtml(input);
    }
}

